namespace sv_172274940be44636ac3b408015ceaa5c.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@rendermode InteractiveServer
@using sv_172274940be44636ac3b408015ceaa5c.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="chat-sidebar">
        <h3 class="sidebar-title">Channels</h3>
        <ul class="channel-list">
            @foreach (var channel in channels)
            {
                <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-header-row">
                        <span class="channel-name"># @channel.Name</span>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </div>
                    @if (!string.IsNullOrWhiteSpace(channel.Description))
                    {
                        <span class="channel-desc">@Truncate(channel.Description, 40)</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="chat-main @(threadOpen ? "" : "chat-main--wide")">
        @if (activeChannel is not null)
        {
            <header class="main-header">
                <h2># @activeChannel.Name</h2>
                <span class="main-header-desc">@activeChannel.Description</span>
            </header>

            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageListScroll">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    <div class="message-row" @onmouseenter="() => hoveredMessageId = msg.Id"
                         @onmouseleave="() => { if (hoveredMessageId == msg.Id) hoveredMessageId = null; }">
                        <div class="message-content-area">
                            <div class="message-meta">
                                <strong class="message-author">@msg.Author</strong>
                                <time class="message-time">@FormatRelativeTime(msg.SentAt)</time>
                            </div>
                            <p class="message-text">@msg.Content</p>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{ var threadInfo = threadSummaries.FirstOrDefault(t => t.RootMessageId == msg.Id); }
                            @if (threadInfo is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @threadInfo.ReplyCount @(threadInfo.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }
                        </div>

                        @if (hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread"
                                        @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                <div class="emoji-picker-wrapper">
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                                    @if (emojiPickerMessageId == msg.Id)
                                    {
                                        <div class="emoji-picker">
                                            @foreach (var emoji in commonEmojis)
                                            {
                                                <button class="emoji-option"
                                                        @onclick="() => ReactAsync(msg.Id, emoji)">@emoji</button>
                                            }
                                        </div>
                                    }
                                </div>
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Type a message…"
                          @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="OnMainKeyDown" />
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(newMessageText)"
                        @onclick="SendMessageAsync">Send</button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="chat-thread-panel">
            <header class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </header>

            <div class="thread-root-quote">
                <strong>@threadRootMessage.Author</strong>
                <p>@threadRootMessage.Content</p>
            </div>

            <div class="thread-messages">
                @foreach (var reply in threadReplies)
                {
                    <div class="message-row thread-reply-row">
                        <div class="message-content-area">
                            <div class="message-meta">
                                <strong class="message-author">@reply.Author</strong>
                                <time class="message-time">@FormatRelativeTime(reply.SentAt)</time>
                            </div>
                            <p class="message-text">@reply.Content</p>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Reply in thread…"
                          @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown" />
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(threadReplyText)"
                        @onclick="SendThreadReplyAsync">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    private List<Channel> channels = new();
    private List<Message> messages = new();
    private List<Message> threadReplies = new();
    private List<ThreadSummary> threadSummaries = new();

    private Channel? activeChannel;
    private int activeChannelId;
    private Message? threadRootMessage;
    private bool threadOpen;

    private string newMessageText = "";
    private string threadReplyText = "";

    private int? hoveredMessageId;
    private int? emojiPickerMessageId;

    private bool isLoadingMore;
    private bool allMessagesLoaded;
    private const int PageSize = 30;

    private ElementReference messageListRef;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🔥", "👀"];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        messages.Clear();
        threadSummaries.Clear();
        allMessagesLoaded = false;
        CloseThread();

        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        await BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();

        await ScrollToBottom();
    }

    private async Task BuildThreadSummaries()
    {
        threadSummaries.Clear();
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        // A message is a thread starter if any other message references it
        var repliesByRoot = messages
            .Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value))
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in repliesByRoot)
        {
            threadSummaries.Add(new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)));
        }

        // Also check via GetThreadAsync for root messages that might have replies not in current page
        foreach (var msg in messages.Where(m => m.ReplyToId is null))
        {
            if (threadSummaries.Any(t => t.RootMessageId == msg.Id))
                continue;

            var thread = await ChatService.GetThreadAsync(msg.Id);
            if (thread.Count > 0)
            {
                threadSummaries.Add(new ThreadSummary(
                    msg.Id,
                    thread.Count,
                    thread.Max(t => t.SentAt)));
            }
        }
    }

    private async Task OnMessageListScroll()
    {
        if (isLoadingMore || allMessagesLoaded) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessages();
        }
    }

    private async Task LoadOlderMessages()
    {
        if (activeChannel is null || allMessagesLoaded) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, PageSize);
        if (older.Count < PageSize)
            allMessagesLoaded = true;

        messages.InsertRange(0, older);
        await BuildThreadSummaries();

        isLoadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageText.Trim(), null);
        messages.Add(sent);
        newMessageText = "";

        await ScrollToBottom();
    }

    private async Task OnMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        threadOpen = true;
        emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
        threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies.Add(sent);
        threadReplyText = "";

        // Update thread summary count
        await BuildThreadSummaries();
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messages.Count);
        }

        if (threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval",
            "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..(maxLength - 1)] + "…";
}

