    display: flex;
    flex-direction: column;
    overflow-y: auto;
}

.sidebar-title {
    padding: 16px 16px 8px;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #27242c;
}

.channel-item.active {
    background: #1164a3;
    border-left-color: #fff;
    color: #fff;
}

.channel-header-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-desc {
    font-size: 0.75rem;
    color: #9e9ea6;
    display: block;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ── Main message area ── */
.chat-main {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #1a1d21;
    transition: width 0.2s ease;
}

.chat-main--wide {
    width: 80%;
}

.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #2c2d30;
    flex-shrink: 0;
}

.main-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.main-header-desc {
    font-size: 0.8rem;
    color: #9e9ea6;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #9e9ea6;
    font-size: 1.1rem;
}

