.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #9e9ea6;
    font-size: 0.85rem;
}

.message-row {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    padding: 6px 8px;
    border-radius: 6px;
    position: relative;
    transition: background 0.1s;
}

.message-row:hover {
    background: #222529;
}

.message-content-area {
    flex: 1;
    min-width: 0;
