.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    color: #fff;
    font-size: 0.9rem;
}

.message-time {
    color: #717274;
    font-size: 0.75rem;
}

.message-text {
    margin: 0;
